Write-Host "==================================================" -ForegroundColor Cyan
Write-Host "  Claude Context Vault - Link Setup" -ForegroundColor Cyan
Write-Host "==================================================" -ForegroundColor Cyan
Write-Host ""

# Check admin
$isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
if (-not $isAdmin) {
    Write-Host "WARNING: Not running as Administrator" -ForegroundColor Yellow
    Write-Host "         Using junctions instead of symlinks" -ForegroundColor Yellow
    Write-Host ""
}

# Verify paths exist
if (-not (Test-Path $claudePath)) {
    Write-Host "ERROR: Claude directory not found: $claudePath" -ForegroundColor Red
    Write-Host "       Install Claude Code first." -ForegroundColor Red
    Write-Host ""
    exit 1
}

