#Requires -Version 5.1
<#
.SYNOPSIS
    Bootstrap Personal Claude Environment

.DESCRIPTION
    Creates symlinks from ~/.claude/ to personal-claude-docs repository.

    This script:
    - Backs up existing .claude files if needed
    - Creates symlinks to enterprise layer (learning, skills, commands, etc.)
    - Creates symlinks to user layer (personal preferences)
    - Verifies setup

.PARAMETER Force
    Remove existing symlinks and recreate them

.PARAMETER BackupExisting
    Backup existing .claude content before creating symlinks

.EXAMPLE
    .\setup-personal.ps1

.EXAMPLE
    .\setup-personal.ps1 -Force -BackupExisting
#>

[CmdletBinding()]
param(
    [Parameter()]
    [switch]$Force,

    [Parameter()]
    [switch]$BackupExisting
)

$ErrorActionPreference = "Stop"

# Colors
function Write-Step { param([string]$Message) Write-Host "→ $Message" -ForegroundColor Cyan }
function Write-Success { param([string]$Message) Write-Host "✓ $Message" -ForegroundColor Green }
function Write-Warning { param([string]$Message) Write-Host "⚠ $Message" -ForegroundColor Yellow }
function Write-Fail { param([string]$Message) Write-Host "✗ $Message" -ForegroundColor Red }

# Header
Write-Host "`n╔════════════════════════════════════════════════════════╗" -ForegroundColor Blue
Write-Host "║   Personal Claude Environment Setup                  ║" -ForegroundColor Blue
Write-Host "║   Eduardo Marquez - personal-claude-docs             ║" -ForegroundColor Blue
Write-Host "╚════════════════════════════════════════════════════════╝`n" -ForegroundColor Blue

# Paths
$claudeRoot = "$env:USERPROFILE\.claude"
$repoRoot = Split-Path (Split-Path $PSScriptRoot -Parent) -Parent
$enterpriseSource = Join-Path $repoRoot ".claude\enterprise"
$userSource = Join-Path $repoRoot ".claude\users\emarquez-personal"

Write-Step "Validating paths..."
Write-Host "  Claude root: $claudeRoot"
Write-Host "  Repository: $repoRoot"
Write-Host "  Enterprise source: $enterpriseSource"
Write-Host "  User source: $userSource"

# Validate
if (-not (Test-Path $claudeRoot)) {
    Write-Fail "Claude directory not found at $claudeRoot"
    Write-Host "Please run Claude Code at least once to initialize ~/.claude/" -ForegroundColor Yellow
    exit 1
}

if (-not (Test-Path $enterpriseSource)) {
    Write-Fail "Enterprise source not found at $enterpriseSource"
    Write-Host "Make sure you're running this script from personal-claude-docs/.claude/scripts/" -ForegroundColor Yellow
    exit 1
}

# Backup existing content if requested
if ($BackupExisting) {
    Write-Step "Backing up existing .claude content..."
    $backupDir = Join-Path $claudeRoot "backup-$(Get-Date -Format 'yyyyMMdd-HHmmss')"

    $foldersToBackup = @("learning", "skills", "commands", "reference", "agents")
    $needsBackup = $false

    foreach ($folder in $foldersToBackup) {
        $path = Join-Path $claudeRoot $folder
        if (Test-Path $path) {
            if (-not $needsBackup) {
                New-Item -ItemType Directory -Path $backupDir -Force | Out-Null
                $needsBackup = $true
            }
            Copy-Item -Path $path -Destination $backupDir -Recurse -Force
            Write-Success "Backed up: $folder"
        }
    }

    if ($needsBackup) {
        Write-Success "Backup saved to: $backupDir"
    } else {
        Write-Host "  Nothing to backup" -ForegroundColor Gray
    }
}

# Define symlinks
$symlinks = @(
    @{
        Name = "learning"
        Source = Join-Path $enterpriseSource "learning"
        Target = Join-Path $claudeRoot "learning"
        Description = "Learning and best practices"
    },
    @{
        Name = "skills"
        Source = Join-Path $enterpriseSource "skills"
        Target = Join-Path $claudeRoot "skills"
        Description = "Reusable skills"
    },
    @{
        Name = "commands"
        Source = Join-Path $enterpriseSource "commands"
        Target = Join-Path $claudeRoot "commands"
        Description = "Custom commands"
    },
    @{
        Name = "reference"
        Source = Join-Path $enterpriseSource "reference"
        Target = Join-Path $claudeRoot "reference"
        Description = "Quick reference docs"
    },
    @{
        Name = "agents"
        Source = Join-Path $enterpriseSource "agents"
        Target = Join-Path $claudeRoot "agents"
        Description = "AI subagents"
    }
)

# Create symlinks
Write-Step "Creating symlinks from .claude to personal-claude-docs..."

foreach ($link in $symlinks) {
    $targetPath = $link.Target
    $sourcePath = $link.Source

    # Check if target exists
    if (Test-Path $targetPath) {
        if ($Force) {
            Write-Warning "Removing existing: $($link.Name)"
            Remove-Item $targetPath -Force -Recurse
        } else {
            Write-Host "  Already exists: $($link.Name)" -ForegroundColor Gray
            continue
        }
    }

    # Verify source exists
    if (-not (Test-Path $sourcePath)) {
        Write-Warning "Source not found: $sourcePath"
        continue
    }

    # Create symlink
    try {
        New-Item -ItemType SymbolicLink -Path $targetPath -Target $sourcePath -Force | Out-Null
        Write-Success "Linked: $($link.Name) → personal-claude-docs"
    } catch {
        Write-Fail "Failed to create symlink for $($link.Name): $_"
    }
}

# Handle CLAUDE.md
Write-Step "Setting up CLAUDE.md..."

$claudeMdSource = Join-Path $enterpriseSource "CLAUDE.md"
$claudeMdTarget = Join-Path $claudeRoot "CLAUDE.md"

if (Test-Path $claudeMdTarget) {
    if ($BackupExisting) {
        $backupPath = "$claudeMdTarget.backup-$(Get-Date -Format 'yyyyMMdd-HHmmss')"
        Copy-Item $claudeMdTarget $backupPath
        Write-Success "Backed up existing CLAUDE.md"
    }

    if ($Force) {
        Remove-Item $claudeMdTarget -Force
    } else {
        Write-Warning "CLAUDE.md already exists (keeping existing)"
        Write-Host "  Run with -Force to replace" -ForegroundColor Yellow
    }
}

if (-not (Test-Path $claudeMdTarget)) {
    New-Item -ItemType SymbolicLink -Path $claudeMdTarget -Target $claudeMdSource -Force | Out-Null
    Write-Success "Linked: CLAUDE.md → personal-claude-docs"
}

# Verify setup
Write-Step "Verifying setup..."

$allGood = $true
foreach ($link in $symlinks) {
    if (Test-Path $link.Target) {
        $item = Get-Item $link.Target
        if ($item.LinkType -eq "SymbolicLink") {
            Write-Host "  ✓ $($link.Name)" -ForegroundColor Green
        } else {
            Write-Host "  ✗ $($link.Name) (not a symlink)" -ForegroundColor Red
            $allGood = $false
        }
    } else {
        Write-Host "  ✗ $($link.Name) (missing)" -ForegroundColor Red
        $allGood = $false
    }
}

# Summary
Write-Host "`n╔════════════════════════════════════════════════════════╗" -ForegroundColor Green
Write-Host "║   ✓ Personal Claude Environment Ready                ║" -ForegroundColor Green
Write-Host "╚════════════════════════════════════════════════════════╝`n" -ForegroundColor Green

Write-Host "Setup complete!" -ForegroundColor Cyan
Write-Host "  • Files live in: " -NoNewline; Write-Host $repoRoot -ForegroundColor Yellow
Write-Host "  • Claude reads from: " -NoNewline; Write-Host $claudeRoot -ForegroundColor Yellow
Write-Host "  • Edit in repo, Claude uses automatically" -ForegroundColor Gray

Write-Host "`nWhat's available:" -ForegroundColor Cyan
Write-Host "  • learning/    - Capture knowledge and best practices"
Write-Host "  • skills/      - Build reusable workflows"
Write-Host "  • commands/    - Create custom /commands"
Write-Host "  • reference/   - Quick lookup docs"
Write-Host "  • agents/      - Specialized AI subagents"

Write-Host "`nNext steps:" -ForegroundColor Cyan
Write-Host "  1. Read: $repoRoot\README.md"
Write-Host "  2. Review: $claudeRoot\CLAUDE.md"
Write-Host "  3. Start using Claude Code - it will load your personal context"
Write-Host "  4. Capture your first learning in learning/best-practices/"
Write-Host "  5. Commit and push to GitHub for backup"

Write-Host "`nGit workflow:" -ForegroundColor Cyan
Write-Host "  cd $repoRoot"
Write-Host "  git add ."
Write-Host '  git commit -m "Add: first learning"'
Write-Host "  git push"

if (-not $allGood) {
    Write-Host "`n⚠ Some symlinks failed to create. Run with -Force to fix." -ForegroundColor Yellow
    exit 1
}

Write-Host ""

