    Write-Host "  Edit content in Obsidian or personal-claude-docs - Claude sees both." -ForegroundColor Gray
} else {
    Write-Host "  Some links missing. Re-run with -Force." -ForegroundColor Yellow
    exit 1
}
Write-Host ""

