    if ($canSymlink) { New-Item -ItemType SymbolicLink -Path $lp -Target $tg -Force | Out-Null }
    else             { cmd /c mklink /J "$lp" "$tg" 2>&1 | Out-Null }

    if (Test-Path $lp) { Write-Ok $lb } else { Write-Fail "${lb}: creation failed" }
}

