1	#Requires -Version 5.1
2	<#
3	.SYNOPSIS
4	    Bootstrap Personal Claude Environment - works on Home, Work, and Laptop.
5	
6	.DESCRIPTION
7	    Creates symlinks from ~/.claude/ to personal-claude-docs enterprise layer.
8	    Also wires Obsidian vault _claude-* folders to the same targets.
9	
10	    Source of truth:   personal-claude-docs/.claude/enterprise/  (this repo)
11	    Claude reads from: ~/.claude/{commands,skills,learning,reference,agents}
12	    Obsidian sees:     {vault}/0X-{Section}/_claude-{name}  (same real dirs)
13	
14	    Auto-detects computer profile by OneDrive location.
15	    Falls back to directory junctions when symlinks require elevation.
16	
17	.PARAMETER Profile
18	    Computer profile: "home" | "work" | "laptop" | "auto" (default: auto)
19	
20	.PARAMETER Force
21	    Remove and recreate existing symlinks/junctions.
22	
23	.PARAMETER BackupExisting
24	    Backup real directories in ~/.claude/ before replacing with symlinks.
25	
26	.EXAMPLE
27	    .\setup-personal.ps1
28	    .\setup-personal.ps1 -Force
29	    .\setup-personal.ps1 -Profile work -Force
30	#>
31	
32	[CmdletBinding()]
33	param(
34	    [ValidateSet("auto","home","work","laptop")]
35	    [string]$Profile = "auto",
36	
37	    [switch]$Force,
38	    [switch]$BackupExisting
39	)
40	
41	$ErrorActionPreference = "Stop"
42	
43	function Write-Step    { param([string]$m) Write-Host "  -> $m" -ForegroundColor Cyan }
44	function Write-Ok      { param([string]$m) Write-Host "  OK  $m" -ForegroundColor Green }
45	function Write-Skip    { param([string]$m) Write-Host "  --  $m" -ForegroundColor Gray }
46	function Write-Warn    { param([string]$m) Write-Host "  !!  $m" -ForegroundColor Yellow }
47	function Write-Fail    { param([string]$m) Write-Host "  XX  $m" -ForegroundColor Red }
48	
49	Write-Host ""
50	Write-Host "============================================" -ForegroundColor Blue
51	Write-Host "  Personal Claude Environment - Bootstrap  " -ForegroundColor Blue
52	Write-Host "============================================" -ForegroundColor Blue
53	Write-Host ""
54	
55	# ─── 1. Detect profile ───────────────────────────────────────────────────────
56	
57	if ($Profile -eq "auto") {
58	    if     (Test-Path "D:\OneDrive\16 - Obsidian\01_Claude_Home") { $Profile = "home" }
59	    elseif (Test-Path "C:\Users\emarquez\OneDrive\16 - Obsidian\01_Claude_Home") { $Profile = "work" }
60	    else {
61	        Write-Warn "Cannot auto-detect profile. Use -Profile home|work|laptop"
62	        Write-Host "  Expected vault paths:"
63	        Write-Host "    home   : D:\OneDrive\16 - Obsidian\01_Claude_Home"
64	        Write-Host "    work   : C:\Users\emarquez\OneDrive\16 - Obsidian\01_Claude_Home"
65	        exit 1
66	    }
67	}
68	
69	switch ($Profile) {
70	    "home" {
71	        $claudeRoot  = "C:\Users\eduar\.claude"
72	        $vaultPath   = "D:\OneDrive\16 - Obsidian\01_Claude_Home"
73	    }
74	    "work" {
75	        $claudeRoot  = "C:\Users\emarquez\.claude"
76	        $vaultPath   = "C:\Users\emarquez\OneDrive\16 - Obsidian\01_Claude_Home"
77	    }
78	    "laptop" {
79	        $claudeRoot  = "$env:USERPROFILE\.claude"
80	        $vaultPath   = "$env:USERPROFILE\OneDrive\16 - Obsidian\01_Claude_Home"
81	    }
82	}
83	
84	# Repo root = two levels up from this script (.claude/scripts/ -> .claude/ -> repo root)
85	$repoRoot        = Split-Path (Split-Path $PSScriptRoot -Parent) -Parent
86	$enterpriseSrc   = Join-Path $repoRoot ".claude\enterprise"
87	$personalSrc     = Join-Path $repoRoot ".claude\users\emarquez-personal"
88	
89	Write-Host "  Profile    : $Profile"
90	Write-Host "  Repo       : $repoRoot"
91	Write-Host "  Claude dir : $claudeRoot"
92	Write-Host "  Vault      : $vaultPath"
93	Write-Host ""
94	
95	# ─── 2. Preflight ────────────────────────────────────────────────────────────
96	
97	$canSymlink = $false
98	try {
99	    $isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole(
100	        [Security.Principal.WindowsBuiltInRole]::Administrator)
101	    $devMode = (Get-ItemProperty "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\AppModelUnlock" `
102	        -ErrorAction SilentlyContinue).AllowDevelopmentWithoutDevLicense -eq 1
103	    $canSymlink = $isAdmin -or $devMode
104	} catch {}
105	
106	$linkMethod = if ($canSymlink) { "symlink" } else { "junction (no admin - fallback)" }
107	Write-Host "  Link method: $linkMethod" -ForegroundColor $(if ($canSymlink) { "Green" } else { "Yellow" })
108	Write-Host ""
109	
110	if (-not (Test-Path $claudeRoot)) {
111	    Write-Fail "Claude dir not found: $claudeRoot"
112	    Write-Host "  Run Claude Code once to initialize it." -ForegroundColor Gray
113	    exit 1
114	}
115	if (-not (Test-Path $enterpriseSrc)) {
116	    Write-Fail "Enterprise source not found: $enterpriseSrc"
117	    Write-Host "  Clone personal-claude-docs first." -ForegroundColor Gray
118	    exit 1
119	}
120	
121	# ─── 3. Helpers ──────────────────────────────────────────────────────────────
122	
123	function Set-Link {
124	    param([string]$LinkPath, [string]$Target, [string]$Label)
125	
126	    if (-not (Test-Path $Target)) {
127	        Write-Warn "$Label : target missing ($Target)"
128	        return
129	    }
130	
131	    if (Test-Path $LinkPath) {
132	        $existing = Get-Item $LinkPath -Force
133	        $isLink   = $existing.Attributes -band [IO.FileAttributes]::ReparsePoint
134	
135	        if ($Force) {
136	            if ($isLink) {
137	                # Remove junction/symlink without touching target contents
138	                try {
139	                    [System.IO.Directory]::Delete($LinkPath)
140	                } catch {
141	                    try { Remove-Item $LinkPath -Force -ErrorAction Stop }
142	                    catch { Write-Warn "$Label : could not remove existing link - $_"; return }
143	                }
144	            } else {
145	                # Real directory - backup if has content, delete if empty
146	                $isEmpty = (@(Get-ChildItem $LinkPath -Force -ErrorAction SilentlyContinue)).Count -eq 0
147	                if ($isEmpty) {
148	                    Remove-Item $LinkPath -Force -Recurse
149	                } elseif ($BackupExisting) {
150	                    $bk = "$LinkPath.bak-$(Get-Date -Format 'yyyyMMdd-HHmmss')"
151	                    Rename-Item $LinkPath $bk
152	                    Write-Ok "$Label : backed up to $(Split-Path $bk -Leaf)"
153	                } else {
154	                    Write-Warn "$Label : real directory with content - use -Force -BackupExisting to replace"
155	                    return
156	                }
157	            }
158	        } else {
159	            if ($isLink) { Write-Skip "$Label : already linked" }
160	            else         { Write-Warn "$Label : real directory exists (use -Force to replace)" }
161	            return
162	        }
163	    }
164	
165	    $parent = Split-Path $LinkPath -Parent
166	    if (-not (Test-Path $parent)) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }
167	
168	    if ($existing.PSIsContainer -or (Test-Path $Target -PathType Container)) {
169	        # Directory link
170	        if ($canSymlink) {
171	            New-Item -ItemType SymbolicLink -Path $LinkPath -Target $Target -Force | Out-Null
172	        } else {
173	            cmd /c mklink /J "$LinkPath" "$Target" 2>&1 | Out-Null
174	        }
175	    } else {
176	        # File link
177	        if ($canSymlink) {
178	            New-Item -ItemType SymbolicLink -Path $LinkPath -Target $Target -Force | Out-Null
179	        } else {
180	            Copy-Item $Target $LinkPath -Force
181	            Write-Warn "$Label : copied (file symlinks need admin - re-run as admin for live link)"
182	            return
183	        }
184	    }
185	
186	    if (Test-Path $LinkPath) { Write-Ok "$Label" }
187	    else                     { Write-Fail "$Label : creation failed" }
188	}
189	
190	# ─── 4. ~/.claude/ symlinks ──────────────────────────────────────────────────
191	
192	Write-Step "Linking ~/.claude/ -> enterprise dirs"
193	Set-Link "$claudeRoot\commands"   "$enterpriseSrc\commands"  "commands"
194	Set-Link "$claudeRoot\skills"     "$enterpriseSrc\skills"    "skills"
195	Set-Link "$claudeRoot\learning"   "$enterpriseSrc\learning"  "learning"
196	Set-Link "$claudeRoot\reference"  "$enterpriseSrc\reference" "reference"
197	Set-Link "$claudeRoot\agents"     "$enterpriseSrc\agents"    "agents"
198	Set-Link "$claudeRoot\enterprise" "$enterpriseSrc"           "enterprise (for @-imports)"
199	Set-Link "$claudeRoot\personal"   "$personalSrc"             "personal   (for @-imports)"
200	
201	# ─── 5. ~/.claude/CLAUDE.md ──────────────────────────────────────────────────
202	
203	Write-Host ""
204	Write-Step "Setting up CLAUDE.md"
205	$claudeMdTarget = "$claudeRoot\CLAUDE.md"
206	$claudeMdSource = "$enterpriseSrc\CLAUDE.md"
207	
208	if ((Test-Path $claudeMdTarget) -and -not $Force) {
209	    Write-Skip "CLAUDE.md : already exists (use -Force to regenerate)"
210	} else {
211	    if (Test-Path $claudeMdTarget) { Remove-Item $claudeMdTarget -Force }
212	
213	    $machineName = switch ($Profile) {
214	        "home"   { "Home (eduar)" }
215	        "work"   { "Work (emarquez)" }
216	        "laptop" { "Laptop ($env:USERNAME)" }
217	    }
218	    $oneDrive = switch ($Profile) {
219	        "home"   { "D:\OneDrive\" }
220	        "work"   { "C:\Users\emarquez\OneDrive\" }
221	        "laptop" { "$env:USERPROFILE\OneDrive\" }
222	    }
223	
224	@"
225	# Claude Global Config - $machineName
226	# Auto-generated by setup-personal.ps1 - edit enterprise/CLAUDE.md for shared config.
227	
228	@enterprise/CLAUDE.md
229	@personal/CLAUDE.md
230	
231	---
232	
233	## Machine: $machineName
234	
235	| Item | Path |
236	|------|------|
237	| OneDrive | ``$oneDrive`` |
238	| Obsidian vault | ``$vaultPath`` |
239	| ClaudeDocs | ``$repoRoot`` |
240	| Claude dir | ``$claudeRoot`` |
241	
242	### New Machine Setup
243	``````powershell
244	git clone https://github.com/Eduardodmb/ClaudeDocs.git "`$env:USERPROFILE\personal-claude-docs"
245	& "`$env:USERPROFILE\personal-claude-docs\.claude\scripts\setup-personal.ps1"
246	``````
247	"@ | Out-File $claudeMdTarget -Encoding utf8
248	
249	    Write-Ok "CLAUDE.md : generated with @enterprise and @personal imports"
250	}
251	
252	# ─── 6. Runtime dirs (local only) ────────────────────────────────────────────
253	
254	Write-Host ""
255	Write-Step "Ensuring runtime directories"
